final:
module RefModule(
    input wire in0,
    input wire in1,
    input wire in2,
    input wire in3,
    input wire [1:0] sel,
    output wire out
);
  wire _tap_in0 = in0 & {1{1'b1}};


assign out = (sel == 2'b00) ? in0 :
             (sel == 2'b01) ? in1 :
             (sel == 2'b10) ? in2 : in3;

endmodule
